python3 -c "
import json, sys, urllib.request, urllib.error, os
args = json.load(sys.stdin)
prompt = (args.get('prompt') or '').strip()
if not prompt:
    print(json.dumps({'success': False, 'error': 'prompt is required'})); sys.exit(0)
working_dir = args.get('working_dir') or os.path.expanduser('~')
working_dir = os.path.expanduser(working_dir)
if not os.path.isdir(working_dir):
    print(json.dumps({'success': False, 'error': f'working_dir does not exist: {working_dir}'})); sys.exit(0)
base = '${MOJO_BASE_URL}'.rstrip('/')
api_key = os.environ.get('MCP_API_KEY', '')
headers = {'Content-Type': 'application/json'}
if api_key:
    headers['MCP-API-Key'] = api_key

def call(tool, arguments):
    payload = {'jsonrpc': '2.0', 'id': 1, 'method': 'tools/call', 'params': {'name': tool, 'arguments': arguments}}
    req = urllib.request.Request(base + '/mcp', data=json.dumps(payload).encode(), headers=headers)
    with urllib.request.urlopen(req, timeout=110) as r:
        return json.loads(r.read())

try:
    create_resp = call('external_agent', {'action': 'backend_session_create', 'server_id': args.get('server_id', '')})
    if 'error' in create_resp:
        print(json.dumps({'success': False, 'error': create_resp['error']})); sys.exit(0)
    session_id = (create_resp.get('result') or {}).get('session_id') or ((create_resp.get('result') or {}).get('data') or {}).get('session_id')
    if not session_id:
        print(json.dumps({'success': False, 'error': 'no session_id in create response', 'raw': create_resp})); sys.exit(0)
    msg_args = {'action': 'backend_session_message', 'session_id': session_id, 'content': prompt, 'server_id': args.get('server_id', '')}
    if args.get('model'):
        msg_args['model'] = args['model']
    msg_resp = call('external_agent', msg_args)
    print(json.dumps({'success': True, 'session_id': session_id, 'response': msg_resp.get('result', msg_resp)}))
except urllib.error.HTTPError as e:
    print(json.dumps({'success': False, 'error': f'HTTP {e.code}: {e.read().decode(errors=\"replace\")[:500]}'}))
except urllib.error.URLError as e:
    print(json.dumps({'success': False, 'error': f'Cannot reach MoJo at {base}: {e.reason}'}))
except Exception as e:
    print(json.dumps({'success': False, 'error': f'{type(e).__name__}: {e}'}))
"
